INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_df98913b-e4c1-56e3-af6e-72789702fe8e','Larson to step down as K-12 principal','By DEANNA ANDERSON','2026-01-28','quadd_extraction','Mountain Lake, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','1','[8]','Larson to step down as K-12 principal\n\nLarson has been with the district since the 2015-2016 school year.\n\nThe Mt. Lake Public School Board has accepted the resignation of K-12 Principal Michelle Larson, effective at the end of the 2025-26 school year. Board members also approved posting the K-12 principal position. Larson joined the district in the 2015-16 school year as the 7-12 high school principal. When the district later reorganized its administrative structure, she became the K-12 principal. She has served through multiple administrative changes and building projects, according to Superintendent Brandon Henning. “Her wisdom, shaped through experience, patience and genuine care, has guided countless decisions and helped others see challenges as opportunities to grow,” Henning said. “She has also been an invaluable resource, always willing to share her knowledge, offer thoughtful advice and support others with confidence and grace. Our school community wishes her all the best as she enters the next chapter of her life.” Larson will be missed by staff, according to Mary Brown, a special education teacher. “She is very good,” Brown said. “She was always on top of everything.” Board Chairman Chad Eken also thanked Larson for her dedication to the school. Other resignations Michelle Larson Joanne Karschnik submitted a resignation effective Jan. 31. Karschnik, who has worked at Town and Country Daycare for 34 years, was thanked by the board for making a positive difference in many lives. Sonja Reed resigned her part- time custodian position but will remain on staff as a substitute custodian. Wyatt Bergling agreed to increase his status from substitute custodian to part-time custodian to fill the vacancy, and the board approved his hiring. Great Start grant As of January 2026, the Great Start Compensation Support payment for November 2025 hours at Town and Country Daycare totaled $3,399. In all, the district has received $87,616 since October 2023. The Great Start grant, provided by the state of Minnesota, helps support child care providers by keeping costs low for families while also ensuring\n\nstaff receive fair wages, Henning said. Roofing project Contractor McPhillips Bros. Roofing Co., the Mt. Lake Public School District and Surety RLI Insurance Co. entered into a binding contract for the upcoming roofing project. Performance and payment are bonded in','Larson to step down as K-12 principal\n\nLarson has been with the district since the 2015-2016 school year.\n\nThe Mt. Lake Public School Board has accepted the resignation of K-12 Principal Michelle Larson, effective at the end of the 2025-26 school year. Board members also approved posting the K-12 principal position. Larson joined the district in the 2015-16 school year as the 7-12 high school principal. When the district later reorganized its administrative structure, she became the K-12 principal. She has served through multiple administrative changes and building projects, according to Superintendent Brandon Henning. “Her wisdom, shaped through experience, patience and genuine care, has guided countless decisions and helped others see challenges as opportunities to grow,” Henning said. “She has also been an invaluable resource, always willing to share her knowledge, offer thoughtful advice and support others with confidence and grace. Our school community wishes her all the best as she enters the next chapter of her life.” Larson will be missed by staff, according to Mary Brown, a special education teacher. “She is very good,” Brown said. “She was always on top of everything.” Board Chairman Chad Eken also thanked Larson for her dedication to the school. Other resignations Michelle Larson Joanne Karschnik submitted a resignation effective Jan. 31. Karschnik, who has worked at Town and Country Daycare for 34 years, was thanked by the board for making a positive difference in many lives. Sonja Reed resigned her part- time custodian position but will remain on staff as a substitute custodian. Wyatt Bergling agreed to increase his status from substitute custodian to part-time custodian to fill the vacancy, and the board approved his hiring. Great Start grant As of January 2026, the Great Start Compensation Support payment for November 2025 hours at Town and Country Daycare totaled $3,399. In all, the district has received $87,616 since October 2023. The Great Start grant, provided by the state of Minnesota, helps support child care providers by keeping costs low for families while also ensuring\n\nstaff receive fair wages, Henning said. Roofing project Contractor McPhillips Bros. Roofing Co., the Mt. Lake Public School District and Surety RLI Insurance Co. entered into a binding contract for the upcoming roofing project. Performance and payment are bonded in',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:48','2026-03-25 00:55:48');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_355c8056-3e22-54d1-b963-19881cedc5bd','Council deals with hazardous, unsafe buildings','By DEANNA ANDERSON','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','1',NULL,'Council deals with hazardous, unsafe buildings\n\nThe city council recently discussed what to do about the former Hiebert’s Greenhouse site.\n\nThe Mt. Lake City Council is taking steps to move ahead with cleaning up a site on Third Avenue with hazardous buildings. City staff has attempted, without success, to remedy the hazardous and unsafe conditions of property at 2100 Third Ave., which is the former Hiebert’s Greenhouse site. A motion was made at the most recent city council meeting to approve Resolution 2-26, ordering repair or removal of hazardous conditions. The motion carried 4-0. The buildings are possibly beyond economic feasibility, according to council member Bryan Bargen. “We do not take pleasure in seeking to enforce the repair or removal of the greenhouse buildings. But the buildings are in complete disarray,” Bargen said. “The facility needs to be cleaned up and repairs done or these buildings and abandoned vehicles need to be removed.” Chip sealing The 2026 chip sealing program for potential roads and chip sealing of the Mt. Lake Trail was discussed. Bargen had concerns about whether the chip seal should be done on the trail. “We need to discuss this and get more information,” Bargen said. “I want to make sure we get good advice before we spend money on this.” Additional information will be gathered and presented to the city council before a decision is made. Other items The council meeting included a second reading of the disruptive intoxication ordinance and a first reading of an update to the city’s tobacco ordinance. The tobacco ordinance reflects state statute, according to City Administrator Michael Mueller. The next city council meeting is set for 5:45 p.m. Monday.','Council deals with hazardous, unsafe buildings\n\nThe city council recently discussed what to do about the former Hiebert’s Greenhouse site.\n\nThe Mt. Lake City Council is taking steps to move ahead with cleaning up a site on Third Avenue with hazardous buildings. City staff has attempted, without success, to remedy the hazardous and unsafe conditions of property at 2100 Third Ave., which is the former Hiebert’s Greenhouse site. A motion was made at the most recent city council meeting to approve Resolution 2-26, ordering repair or removal of hazardous conditions. The motion carried 4-0. The buildings are possibly beyond economic feasibility, according to council member Bryan Bargen. “We do not take pleasure in seeking to enforce the repair or removal of the greenhouse buildings. But the buildings are in complete disarray,” Bargen said. “The facility needs to be cleaned up and repairs done or these buildings and abandoned vehicles need to be removed.” Chip sealing The 2026 chip sealing program for potential roads and chip sealing of the Mt. Lake Trail was discussed. Bargen had concerns about whether the chip seal should be done on the trail. “We need to discuss this and get more information,” Bargen said. “I want to make sure we get good advice before we spend money on this.” Additional information will be gathered and presented to the city council before a decision is made. Other items The council meeting included a second reading of the disruptive intoxication ordinance and a first reading of an update to the city’s tobacco ordinance. The tobacco ordinance reflects state statute, according to City Administrator Michael Mueller. The next city council meeting is set for 5:45 p.m. Monday.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:49','2026-03-25 00:55:49');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_e9c646d3-d27b-5d7c-b472-b6a66099c660','Butterfield secures $1.05M for upgrades','By JEREMY BEHNKE','2026-01-28','quadd_extraction','Butterfield, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','1','[8]','Butterfield secures $1.05M for upgrades\n\nFederal funding announced by Rep. Brad Finstad will support major wastewater improvements in the city.\n\nButterfield is in line to receive $1.05 million in federal funding to help pay for major upgrades to the city’s wastewater treatment system, which is part of a rural water infrastructure package announced by U.S. Rep. Brad Finstad. The funding was included in the federal Fiscal Year 2026 package that gives $11.4 million toward water and utility projects across the state. Butterfield’s share will go toward improvements at its wastewater treatment facility. “This federal investment supports community projects such as pipeline replacements, contamination remediation, new wells, filtration systems and upgraded treatment facilities,” Finstad said in a statement. “This funding will help communities across southern Minnesota ensure reliable access to clean drinking water, protect public health, and reduce the risk of system failures.” Finstad said the funding is part of 11 community project requests for cities across the district, including Blooming Prairie, Butterfield, Dennison, Eagle Lake, Manchester, Nerstrand, Pine Island, Okabena, Pemberton, Rochester and Trimont. “I’m grateful for the opportunity to help bring these federal investments home to southern Minnesota,” Finstad said in a statement. “It’s an honor to serve in congress and advocate for this much-needed funding that strengthens critical water and utility infrastructure and supports the\n\nlong-term vitality of our communities.” Butterfield Mayor Mark Warner said the news came as a surprise. “We knew it had been filed because the previous council and mayor had filed it,” Warner said. “Our city clerk said it had been filed, but nobody really knew what was coming.” Warner said he was contacted by U.S. Sen. Amy Klobuchar’s office after the award was announced. The funding is specifically for wastewater — not drinking water — though some drinking water improvements could be bundled into the project once construction begins. “This is for wastewater — sewage water,” Warner said. “That’s where the big project is: updating our lift stations, sanitary sewer lines and treatment center. “Once we open streets up and start digging, I would assume we’ll also look at freshwater changes because you deal with water mains,” Warner said. “But the majority of the money is earmarked for wastewater treatment.” The mayor cautioned the funding represents only the first step in a longer process. “This bill still has to be signed by the president,” Warner said. “If it isn’t signed, we don’t get anything, but they’re hopeful it will be.” The city is also pursuing state funding and low-interest loans to cover remaining costs. “We’re trying to get funding from the state government now,” Warner said. “Once we get state approval, then we go to USDA or another lender for long- term, low-interest loans.” Even with the federal funding, Warner said it will still take time before work can begin. “It would be nice to break ground this year, but unless the money comes through, you still have to bid the jobs, and that takes time,” he said.','Butterfield secures $1.05M for upgrades\n\nFederal funding announced by Rep. Brad Finstad will support major wastewater improvements in the city.\n\nButterfield is in line to receive $1.05 million in federal funding to help pay for major upgrades to the city’s wastewater treatment system, which is part of a rural water infrastructure package announced by U.S. Rep. Brad Finstad. The funding was included in the federal Fiscal Year 2026 package that gives $11.4 million toward water and utility projects across the state. Butterfield’s share will go toward improvements at its wastewater treatment facility. “This federal investment supports community projects such as pipeline replacements, contamination remediation, new wells, filtration systems and upgraded treatment facilities,” Finstad said in a statement. “This funding will help communities across southern Minnesota ensure reliable access to clean drinking water, protect public health, and reduce the risk of system failures.” Finstad said the funding is part of 11 community project requests for cities across the district, including Blooming Prairie, Butterfield, Dennison, Eagle Lake, Manchester, Nerstrand, Pine Island, Okabena, Pemberton, Rochester and Trimont. “I’m grateful for the opportunity to help bring these federal investments home to southern Minnesota,” Finstad said in a statement. “It’s an honor to serve in congress and advocate for this much-needed funding that strengthens critical water and utility infrastructure and supports the\n\nlong-term vitality of our communities.” Butterfield Mayor Mark Warner said the news came as a surprise. “We knew it had been filed because the previous council and mayor had filed it,” Warner said. “Our city clerk said it had been filed, but nobody really knew what was coming.” Warner said he was contacted by U.S. Sen. Amy Klobuchar’s office after the award was announced. The funding is specifically for wastewater — not drinking water — though some drinking water improvements could be bundled into the project once construction begins. “This is for wastewater — sewage water,” Warner said. “That’s where the big project is: updating our lift stations, sanitary sewer lines and treatment center. “Once we open streets up and start digging, I would assume we’ll also look at freshwater changes because you deal with water mains,” Warner said. “But the majority of the money is earmarked for wastewater treatment.” The mayor cautioned the funding represents only the first step in a longer process. “This bill still has to be signed by the president,” Warner said. “If it isn’t signed, we don’t get anything, but they’re hopeful it will be.” The city is also pursuing state funding and low-interest loans to cover remaining costs. “We’re trying to get funding from the state government now,” Warner said. “Once we get state approval, then we go to USDA or another lender for long- term, low-interest loans.” Even with the federal funding, Warner said it will still take time before work can begin. “It would be nice to break ground this year, but unless the money comes through, you still have to bid the jobs, and that takes time,” he said.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:49','2026-03-25 00:55:49');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_7e5e8920-5b7f-57dd-b87b-920d4defaa9b','Fun is elementary','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','1',NULL,'Fun is elementary\n\nThursday capped an eventful week for students at Mt. Lake Public Elementary School. The Mt. Lake Area-Comfrey girls basketball team celebrated Elementary Week by having team members serve as mentors in elementary classrooms. On Thursday afternoon, the entire elementary assembled in the auditorium for a literacy event. The event featured students in Jessica Svehla’s junior English class dressing up and acting as the key players, as Svehla read the book “The Day the Crayons Quit” by Drew Daywalt. In the book, a boy named Duncan discovers his crayons have quit and had written letters detailing their grievances, such as Yellow and Orange fighting over who is the true color of the sun. Following the performance, students had a chance to select a book to keep from tables, arranged by grade-level materials.','Fun is elementary\n\nThursday capped an eventful week for students at Mt. Lake Public Elementary School. The Mt. Lake Area-Comfrey girls basketball team celebrated Elementary Week by having team members serve as mentors in elementary classrooms. On Thursday afternoon, the entire elementary assembled in the auditorium for a literacy event. The event featured students in Jessica Svehla’s junior English class dressing up and acting as the key players, as Svehla read the book “The Day the Crayons Quit” by Drew Daywalt. In the book, a boy named Duncan discovers his crayons have quit and had written letters detailing their grievances, such as Yellow and Orange fighting over who is the true color of the sun. Following the performance, students had a chance to select a book to keep from tables, arranged by grade-level materials.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:49','2026-03-25 00:55:49');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_343ae955-09e1-5780-8f60-174c6ec0fdbf','Sokolofsky continues to promote Bingham Lake','By JEREMY BEHNKE','2026-01-28','quadd_extraction','Bingham Lake, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','1','[8]','Sokolofsky continues to promote Bingham Lake\n\nThe Bingham Lake mayor wants to continue to promote new housing in the city.\n\nRyan Sokolofsky is entering the final year of his term as mayor of Bingham Lake. Sokolofsky has served as mayor since 2019 and said his focus during the final year of his term will be continuing efforts to promote new housing in the community while also addressing infrastructure updates. He and his significant other, Jodi, have four daughters. Jodi works at Hy-Vee as a retail product specialist. Sokolofsky grew up in Jeffers and is a graduate of Red Rock Central High School. He moved to Bingham Lake in 2014. In his spare time, Sokolofsky enjoys fishing, hunting, working on home projects and being involved with a local sportsmen’s club. Q In your opinion, how did 2025 go for the city of Bingham Lake? A Ryan\n\nSokolofsky SOKOLOFSKY: For Bingham Lake, 2025 was good. We didn’t face any major issues. What is the top priority facing the city in 2026? A SOKOLOFSKY: Not one thing comes to mind. We are always trying to keep up with infrastructure updates as needed. Currently we’re still working on drainage upgrades and keeping the other systems in good working order. Q Is the city promoting any potential new businesses at this point? A SOKOLOFSKY: We are not promoting the city but we’re certainly welcoming new businesses at this time. How important is it for the city to continue to promote new housing? A SOKOLOFSKY: We like to see new housing in the area. Home construction and renovations continued this past year. It’s exciting to know citizens enjoy the Bingham Lake area. Q What is the current condition of the city’s streets and sewage? A SOKOLOFSKY: Our streets are in good shape. Our water\n\nand sewer systems are doing very good as well. Q What are some goals/ projects for the city in 2026? SOKOLOFSKY: We are in the beginnings of a large tree project at the city park, with spring time that will get underway. The trees in the city park are old and dying. There is also a large number of ash trees so we are removing those because of emerald ash borer. I don’t know the number of trees we are removing, but we will add more trees than we remove. We will plant a wide variety of tree species.','Sokolofsky continues to promote Bingham Lake\n\nThe Bingham Lake mayor wants to continue to promote new housing in the city.\n\nRyan Sokolofsky is entering the final year of his term as mayor of Bingham Lake. Sokolofsky has served as mayor since 2019 and said his focus during the final year of his term will be continuing efforts to promote new housing in the community while also addressing infrastructure updates. He and his significant other, Jodi, have four daughters. Jodi works at Hy-Vee as a retail product specialist. Sokolofsky grew up in Jeffers and is a graduate of Red Rock Central High School. He moved to Bingham Lake in 2014. In his spare time, Sokolofsky enjoys fishing, hunting, working on home projects and being involved with a local sportsmen’s club. Q In your opinion, how did 2025 go for the city of Bingham Lake? A Ryan\n\nSokolofsky SOKOLOFSKY: For Bingham Lake, 2025 was good. We didn’t face any major issues. What is the top priority facing the city in 2026? A SOKOLOFSKY: Not one thing comes to mind. We are always trying to keep up with infrastructure updates as needed. Currently we’re still working on drainage upgrades and keeping the other systems in good working order. Q Is the city promoting any potential new businesses at this point? A SOKOLOFSKY: We are not promoting the city but we’re certainly welcoming new businesses at this time. How important is it for the city to continue to promote new housing? A SOKOLOFSKY: We like to see new housing in the area. Home construction and renovations continued this past year. It’s exciting to know citizens enjoy the Bingham Lake area. Q What is the current condition of the city’s streets and sewage? A SOKOLOFSKY: Our streets are in good shape. Our water\n\nand sewer systems are doing very good as well. Q What are some goals/ projects for the city in 2026? SOKOLOFSKY: We are in the beginnings of a large tree project at the city park, with spring time that will get underway. The trees in the city park are old and dying. There is also a large number of ash trees so we are removing those because of emerald ash borer. I don’t know the number of trees we are removing, but we will add more trees than we remove. We will plant a wide variety of tree species.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:49','2026-03-25 00:55:49');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_d011f205-48a2-59e8-b3dc-9e6e4074c92f','Making everyone feel welcome','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','2',NULL,'Making everyone feel welcome\n\nJULIA BRINKMAN Student Voice Columnist thoughts because they will get judged or hated on. I am not saying one should abandon his or her religion. I am just saying the school should be mindful of others when sharing beliefs to respect one another. Having an open mind, makes one a much better person and makes one a lot more pleasing. During interviews I was able to get a couple opinions on this subject. One student said, “It feels as though we get looked past and nobody cares about our particular religion and beliefs because the majority have the same beliefs.” Another student shared, “Our school and students overpower one religion and do not let students speak their opinions and have a voice.”','Making everyone feel welcome\n\nJULIA BRINKMAN Student Voice Columnist thoughts because they will get judged or hated on. I am not saying one should abandon his or her religion. I am just saying the school should be mindful of others when sharing beliefs to respect one another. Having an open mind, makes one a much better person and makes one a lot more pleasing. During interviews I was able to get a couple opinions on this subject. One student said, “It feels as though we get looked past and nobody cares about our particular religion and beliefs because the majority have the same beliefs.” Another student shared, “Our school and students overpower one religion and do not let students speak their opinions and have a voice.”',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:49','2026-03-25 00:55:49');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_bc3496a7-0ad6-5b85-86fd-47cc7a48c808','Crayons quitting','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','2',NULL,'Crayons quitting\n\nLast week’s literacy event at Mt. Lake Public Elementary School featured a special performance. Students in Jessica Svehla’s junior English class dressed in costume for a special and performance of “The Day the Crayons Quit” by Drew Daywalt. In the book, a boy named Duncan discovers his crayons have quit and had written letters detailing their grievances, such as Yellow and Orange fighting over who is the true color of the sun, Pink complaining about lack of use and Peach complaining that peeling of the wrapper had left him nearly naked. After the reading, elementary students were each able to select a book to keep from tables arranged by grade level. The event was made possible through a literacy grant received by the Mt. Lake Public school district.','Crayons quitting\n\nLast week’s literacy event at Mt. Lake Public Elementary School featured a special performance. Students in Jessica Svehla’s junior English class dressed in costume for a special and performance of “The Day the Crayons Quit” by Drew Daywalt. In the book, a boy named Duncan discovers his crayons have quit and had written letters detailing their grievances, such as Yellow and Orange fighting over who is the true color of the sun, Pink complaining about lack of use and Peach complaining that peeling of the wrapper had left him nearly naked. After the reading, elementary students were each able to select a book to keep from tables arranged by grade level. The event was made possible through a literacy grant received by the Mt. Lake Public school district.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:50','2026-03-25 00:55:50');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_5223ba6f-4fad-5e4f-b146-a04aa2b305f1','Car/semi crash on Highway 60','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','2',NULL,'Car/semi crash on Highway 60\n\nAccording to the State Patrol, a 2020 Ford, driven by Shawn Mendel of Worthing, South Dakota, and a 2023 Peterbilt semi, driven by Zakaria El Barhmi of St. Paul, were both westbound on Highway 60 when they collided on the icy, snow-covered roadway. A passenger in the Ford, David Florey of Worthing, S.D., was transported to Windom Area Health with non-life-threatening injuries. Assisting the State Patrol at the scene were the Cottonwood County Sheriff’s Department, Mt. Lake Police Department, Mt. Lake Fire Department and Mt. Lake Ambulance. GOP caucus will be Tuesday The Republican party precinct caucuses will be held Tuesday, beginning at 7 p.m., at the Cottonwood County Historical Society Museum conference room, located at 812 Fourth Avenue in Windom. Registration starts at 6:15 p.m., with the caucus starting at 7 p.m. The caucus is for all precincts within the county, and will include electing delegates and alternates for the county and endorsing conventions, discussing and submitting resolutions for the party platform and conducting a straw poll for governor. DFL caucuses are Tuesday The DFL precinct caucuses will be held Tuesday at the BARC (1012 Fifth Avenue, Windom) and at the Westbrook Senior Center (849 Fifth Street, Westbrook). Registration starts at 6:30 p.m., with the caucus starting at 7 p.m. Caucuses at the BARC will include Carson, Dale, Delton, Great Bend, Lakeside, Midway, Mt. Lake, Selma and Springfield townships, as well as the cities of Windom, Mt. Lake and Bingham Lake. DIY aroma stone craft class The Butterfield branch of the Watonwan County Library and Multicultural Learning Center will host a special craft class Monday at 3 p.m. Adults are invited to learn how to make their own aroma stones, which are perfect for adding fresh scents to areas of homes or offices. Spots are limited. Call 507-956-2361 to sign up. Other activities and events on the schedule at local Watonwan County Library branches include: • Knitting club, Thursday at St. James, 5 p.m.: All levels of experience are welcome, whether you want to learn or have a project you need help to finish. • Button making, Friday at St. James, 3:30 p.m.: Kids in grades 3-6 are invited to unleash their inner artist by creating their own button masterpiece. • Puzzle challenge, Feb. 5 at St. James, 6:30 p.m.: Adults are invited to sign up as a team of four to take on the puzzle challenge. The first team to finish the puzzle wins bragging rights. Call 507-375-1278 to register. • Cribbage club, Feb. 7 at St. James, 10 a.m.: Whether you are a seasoned pro or are just learning the game, players of all skill levels are welcome. Refreshments will be provided. The library asks that any children be accompanied by an adult.','Car/semi crash on Highway 60\n\nAccording to the State Patrol, a 2020 Ford, driven by Shawn Mendel of Worthing, South Dakota, and a 2023 Peterbilt semi, driven by Zakaria El Barhmi of St. Paul, were both westbound on Highway 60 when they collided on the icy, snow-covered roadway. A passenger in the Ford, David Florey of Worthing, S.D., was transported to Windom Area Health with non-life-threatening injuries. Assisting the State Patrol at the scene were the Cottonwood County Sheriff’s Department, Mt. Lake Police Department, Mt. Lake Fire Department and Mt. Lake Ambulance. GOP caucus will be Tuesday The Republican party precinct caucuses will be held Tuesday, beginning at 7 p.m., at the Cottonwood County Historical Society Museum conference room, located at 812 Fourth Avenue in Windom. Registration starts at 6:15 p.m., with the caucus starting at 7 p.m. The caucus is for all precincts within the county, and will include electing delegates and alternates for the county and endorsing conventions, discussing and submitting resolutions for the party platform and conducting a straw poll for governor. DFL caucuses are Tuesday The DFL precinct caucuses will be held Tuesday at the BARC (1012 Fifth Avenue, Windom) and at the Westbrook Senior Center (849 Fifth Street, Westbrook). Registration starts at 6:30 p.m., with the caucus starting at 7 p.m. Caucuses at the BARC will include Carson, Dale, Delton, Great Bend, Lakeside, Midway, Mt. Lake, Selma and Springfield townships, as well as the cities of Windom, Mt. Lake and Bingham Lake. DIY aroma stone craft class The Butterfield branch of the Watonwan County Library and Multicultural Learning Center will host a special craft class Monday at 3 p.m. Adults are invited to learn how to make their own aroma stones, which are perfect for adding fresh scents to areas of homes or offices. Spots are limited. Call 507-956-2361 to sign up. Other activities and events on the schedule at local Watonwan County Library branches include: • Knitting club, Thursday at St. James, 5 p.m.: All levels of experience are welcome, whether you want to learn or have a project you need help to finish. • Button making, Friday at St. James, 3:30 p.m.: Kids in grades 3-6 are invited to unleash their inner artist by creating their own button masterpiece. • Puzzle challenge, Feb. 5 at St. James, 6:30 p.m.: Adults are invited to sign up as a team of four to take on the puzzle challenge. The first team to finish the puzzle wins bragging rights. Call 507-375-1278 to register. • Cribbage club, Feb. 7 at St. James, 10 a.m.: Whether you are a seasoned pro or are just learning the game, players of all skill levels are welcome. Refreshments will be provided. The library asks that any children be accompanied by an adult.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:50','2026-03-25 00:55:50');
