INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_461eecab-ba19-556a-98de-45ee5559863b','n Echoes of the past','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','2','[3]','n Echoes of the past\n\nJan. 27, 2016 As Butterfield-Odin’s school heads toward spring, it seems the district has more questions than answers. What does the future hold for Superintendent/ Principal Lisa Shellum? Who will lead the school into the fall of 2016? What will it take to unite residents who disagree about the direction of the district? It’s clear that even the school board cannot agree on what is best for Butterfield-Odin schools. At Thursday’s meeting, the board voted 4-3 to place Shellum on paid administrative leave. Favoring Shellum’s leave were Anders Pierson, Leon Wenner, Tammy Wolle and Chairman Joel Penner. Opposing the motion were board members Renae\n\nJan. 24, 1996 A long-awaited court order was issued last week and the good news was brought to the Mt. Lake City Council at its Tuesday night meeting by City Attorney David Jungas. It’s official. After going through all the correct procedures, the city finally has the right to demolish what’s left of the burned-out Siha Furniture store. The court order, dated Jan. 16, said that because the city had requested Siha Doungvilay, owner of Siha Furniture, to demolish the building because it was unsafe following the March 3, 1995 fire. Siha did not respond. The city, now, has been granted a request to “remedy the hazardous and unsafe condition of the property, and to raze all of the structures located thereon. The city was ordered to keep 30 YEARS AGO','n Echoes of the past\n\nJan. 27, 2016 As Butterfield-Odin’s school heads toward spring, it seems the district has more questions than answers. What does the future hold for Superintendent/ Principal Lisa Shellum? Who will lead the school into the fall of 2016? What will it take to unite residents who disagree about the direction of the district? It’s clear that even the school board cannot agree on what is best for Butterfield-Odin schools. At Thursday’s meeting, the board voted 4-3 to place Shellum on paid administrative leave. Favoring Shellum’s leave were Anders Pierson, Leon Wenner, Tammy Wolle and Chairman Joel Penner. Opposing the motion were board members Renae\n\nJan. 24, 1996 A long-awaited court order was issued last week and the good news was brought to the Mt. Lake City Council at its Tuesday night meeting by City Attorney David Jungas. It’s official. After going through all the correct procedures, the city finally has the right to demolish what’s left of the burned-out Siha Furniture store. The court order, dated Jan. 16, said that because the city had requested Siha Doungvilay, owner of Siha Furniture, to demolish the building because it was unsafe following the March 3, 1995 fire. Siha did not respond. The city, now, has been granted a request to “remedy the hazardous and unsafe condition of the property, and to raze all of the structures located thereon. The city was ordered to keep 30 YEARS AGO',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:50','2026-03-25 00:55:50');
