INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_5f323f9c-0161-505c-973e-71e4951339a4','2026 Election','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','2',NULL,'2026 Election\n\nCentral Minnesota. Knoll brings extensive experience in healthcare leadership, not-for-profit management and public policy. He has testified at the Capitol and worked directly with lawmakers on issues including not-for-profit sales tax reform, Medicaid reimbursement issues and regulatory burdens impacting rural senior care providers. Knoll believes his experience, values and skill set make him uniquely qualified to serve District 21. “Our region deserves representation that protects rural healthcare, strengthens public safety, supports strong schools, defends constitutional rights, champions agriculture and small busi','2026 Election\n\nCentral Minnesota. Knoll brings extensive experience in healthcare leadership, not-for-profit management and public policy. He has testified at the Capitol and worked directly with lawmakers on issues including not-for-profit sales tax reform, Medicaid reimbursement issues and regulatory burdens impacting rural senior care providers. Knoll believes his experience, values and skill set make him uniquely qualified to serve District 21. “Our region deserves representation that protects rural healthcare, strengthens public safety, supports strong schools, defends constitutional rights, champions agriculture and small busi',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:50','2026-03-25 00:55:50');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_00535890-289c-5134-8d29-7f7403d9bbee','Seated on a school bus','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','3',NULL,'Seated on a school bus\n\nQuestion: I know it’s discouraged but is it actually illegal for students to be standing on a school bus while it is moving? Trooper Troy says: Minnesota state law says no person shall stand in a school bus when the bus is in motion. In addition, the aisle and emergency exit of a school bus shall be kept unobstructed at all times when children are being transported. TROY CHRISTIANSON • Traffic traveling the opposite direction on a divided roadway with a separating median such as a cement wall or boulevard is not required to stop. • Motorists should slow down, pay attention and anticipate school children and buses, especially in neighborhoods and school zones.','Seated on a school bus\n\nQuestion: I know it’s discouraged but is it actually illegal for students to be standing on a school bus while it is moving? Trooper Troy says: Minnesota state law says no person shall stand in a school bus when the bus is in motion. In addition, the aisle and emergency exit of a school bus shall be kept unobstructed at all times when children are being transported. TROY CHRISTIANSON • Traffic traveling the opposite direction on a divided roadway with a separating median such as a cement wall or boulevard is not required to stop. • Motorists should slow down, pay attention and anticipate school children and buses, especially in neighborhoods and school zones.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:50','2026-03-25 00:55:50');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_70ac8532-ae24-5148-bbcc-6cdd37e74c53','ML one act play advances','By JEREMY BEHNKE','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','4',NULL,'ML one act play advances\n\nMt. Lake’s one act play team advanced to the Section 2A competition after taking first at the Subsection 7 competition this past weekend with their performance of “Pearl.” Mt. Lake will compete at 1 p.m. on Saturday in Waseca for a chance to go to the state competition at St. Catherine University in St. Paul on Feb. 6. Director Travis Smith said the team didn’t seem nervous at all when performing despite having a younger, less- experienced team this year. He said Mt. Lake’s one act team has advanced to the section meet in all five years he’s been the director.','ML one act play advances\n\nMt. Lake’s one act play team advanced to the Section 2A competition after taking first at the Subsection 7 competition this past weekend with their performance of “Pearl.” Mt. Lake will compete at 1 p.m. on Saturday in Waseca for a chance to go to the state competition at St. Catherine University in St. Paul on Feb. 6. Director Travis Smith said the team didn’t seem nervous at all when performing despite having a younger, less- experienced team this year. He said Mt. Lake’s one act team has advanced to the section meet in all five years he’s been the director.',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:51','2026-03-25 00:55:51');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_77a1014e-4f7b-53e6-9167-a9220ed1535c','Cobras take fourth at Parkston Tourney','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','5','[6]','Cobras take fourth at Parkston Tourney\n\nCobras was Kameron Koerner, who had a bye into the semifinals at 150 pounds. He then won a technical fall and a 10-2 major decision over Isaac Johnson of Clark-Willow Lake to win the championship. Jacob Lopez added a third- place finish at 120 pounds. Dagen Hansen finished third at 144 pounds. Damien Davison captured third place at 165 pounds. Damian Aguirre placed fourth at 175 pounds. Jose Luna finished sixth at 126 pounds and Keanin\n\nLinscheid finished sixth at 132 pounds. PARKSTON LITTLE B TOURNAMENT Team results: 1. Clark-Willow Lake 181. 2. Parkston 168˝. 3. Howard 136. 4t. WMLBO 122. 4t. McCook Central/Montrose 122. 6. Mt. Vernon/Plankinton/Corsica-Stickney 121˝. 7. Miller/Highmore-Harrold 108. 8. Garretson 106. 9. Webster 84. 10. Bennett County 67. 11. Wessington Springs/Woonsocket/Wolsey-Wessington 57˝. 12. Canistota 62. 13. Marion/Freeman 45. 14. Scotland 37˝. 15. Baltic 35. 16. Hanson 19. Cobra Results 106: Open. 113: Open 120: Jacob Lopez TF Channing Bartlett (MCM) 15-0; Cade Gaikowski (CWL) MD Lopez 19-8; Lopez pin Bentley Roth (Parkston) 1:50; Lopez dec. Kale Hofer (MVPCS) 7-0. Third place 126: Jose Luna def. Skylar Kussatz (MVPCS) by injury default; Parker Randall (MCM) pin Luna 3:23; Luna pin Owan Anderson (MF) 0:50; Preston Aesoph (MHH) TF Luna 18-0; Aydden Trautmann (Scotland) pin Luna 2:50. Sixth place 132: Chase Arend (Garretson) TF Keanin Linscheid 15-0; Linscheid pin Wyatt Carter (Canistota) 0:37; Linscheid pin Aksel Gjerde (CWL) 1:49; Kiptyn Schaefers (Parkston) pin Linscheid 4:17; Chase Arend (Garretson) dec. Linscheid 7-1. Sixth place 138: Open. 144: Dagen Hansen pin Damian Severson (CWL) 5:05; Chase Hurd (MHH) pin Hansen 2:54; Hansen pin Koda Popkes (Canistota) 1:36; Hansen MD Logan Foster (CWL) 11-2. Third place 150: Kameron Koerner TF Michael Blau (MF) 19-4; Koerner MD Isaac Johnson (CWL) 10-2. Champion 157: Open. 165: Damien Davison pin Eli Remacle (Canistota) 1:08; Davison pin Jordan Risse (BC) 2:00; Paxton Nedved (MVPCS) dec. Davison 6-1; Davison pin Payton Nedved (MVPCS) 2:19; Davison dec. Quayden Culbert (Parkston) 9-3. Third place 175: Nathan Hubsch (Webster) dec. Damian Aguirre 7-2; Aguirre dec. Pierre Robinson (WMLBO) 6-2; Aguirre pin Ty VanHolland (Garretson) 2:26; Aguirre dec. Tucker Peterson (MCM) 3-2 on UTB; Joshua Popkes (Canistota) dec. Aguirre 8-3. Fourth place 175 (unattached): Ethan Hoffman (MVPCS) MD Pierre Robinson 12-4; Robinson pin Ridge Moe (CWL) 2:46; Damian Aguirre (WMLBO) dec. Robinson 6-2. 190: Open. 215: Open. 285: Open. Cobras drop two Windom/Mt. Lake/Butterfield/Odin dropped a pair of decisions Thursday at St. James. The Cobras lost 52-10 to Jackson County Central, then dropped a 36-35 decision','Cobras take fourth at Parkston Tourney\n\nCobras was Kameron Koerner, who had a bye into the semifinals at 150 pounds. He then won a technical fall and a 10-2 major decision over Isaac Johnson of Clark-Willow Lake to win the championship. Jacob Lopez added a third- place finish at 120 pounds. Dagen Hansen finished third at 144 pounds. Damien Davison captured third place at 165 pounds. Damian Aguirre placed fourth at 175 pounds. Jose Luna finished sixth at 126 pounds and Keanin\n\nLinscheid finished sixth at 132 pounds. PARKSTON LITTLE B TOURNAMENT Team results: 1. Clark-Willow Lake 181. 2. Parkston 168˝. 3. Howard 136. 4t. WMLBO 122. 4t. McCook Central/Montrose 122. 6. Mt. Vernon/Plankinton/Corsica-Stickney 121˝. 7. Miller/Highmore-Harrold 108. 8. Garretson 106. 9. Webster 84. 10. Bennett County 67. 11. Wessington Springs/Woonsocket/Wolsey-Wessington 57˝. 12. Canistota 62. 13. Marion/Freeman 45. 14. Scotland 37˝. 15. Baltic 35. 16. Hanson 19. Cobra Results 106: Open. 113: Open 120: Jacob Lopez TF Channing Bartlett (MCM) 15-0; Cade Gaikowski (CWL) MD Lopez 19-8; Lopez pin Bentley Roth (Parkston) 1:50; Lopez dec. Kale Hofer (MVPCS) 7-0. Third place 126: Jose Luna def. Skylar Kussatz (MVPCS) by injury default; Parker Randall (MCM) pin Luna 3:23; Luna pin Owan Anderson (MF) 0:50; Preston Aesoph (MHH) TF Luna 18-0; Aydden Trautmann (Scotland) pin Luna 2:50. Sixth place 132: Chase Arend (Garretson) TF Keanin Linscheid 15-0; Linscheid pin Wyatt Carter (Canistota) 0:37; Linscheid pin Aksel Gjerde (CWL) 1:49; Kiptyn Schaefers (Parkston) pin Linscheid 4:17; Chase Arend (Garretson) dec. Linscheid 7-1. Sixth place 138: Open. 144: Dagen Hansen pin Damian Severson (CWL) 5:05; Chase Hurd (MHH) pin Hansen 2:54; Hansen pin Koda Popkes (Canistota) 1:36; Hansen MD Logan Foster (CWL) 11-2. Third place 150: Kameron Koerner TF Michael Blau (MF) 19-4; Koerner MD Isaac Johnson (CWL) 10-2. Champion 157: Open. 165: Damien Davison pin Eli Remacle (Canistota) 1:08; Davison pin Jordan Risse (BC) 2:00; Paxton Nedved (MVPCS) dec. Davison 6-1; Davison pin Payton Nedved (MVPCS) 2:19; Davison dec. Quayden Culbert (Parkston) 9-3. Third place 175: Nathan Hubsch (Webster) dec. Damian Aguirre 7-2; Aguirre dec. Pierre Robinson (WMLBO) 6-2; Aguirre pin Ty VanHolland (Garretson) 2:26; Aguirre dec. Tucker Peterson (MCM) 3-2 on UTB; Joshua Popkes (Canistota) dec. Aguirre 8-3. Fourth place 175 (unattached): Ethan Hoffman (MVPCS) MD Pierre Robinson 12-4; Robinson pin Ridge Moe (CWL) 2:46; Damian Aguirre (WMLBO) dec. Robinson 6-2. 190: Open. 215: Open. 285: Open. Cobras drop two Windom/Mt. Lake/Butterfield/Odin dropped a pair of decisions Thursday at St. James. The Cobras lost 52-10 to Jackson County Central, then dropped a 36-35 decision',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:51','2026-03-25 00:55:51');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_abc03102-9bc7-5d1e-bb59-975951d8978b','the foxes of North America','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','5','[6]','the foxes of North America\n\nGood luck with that! It’s been interesting to watch the ebb and flow of fox populations in southwest Minnesota. And, for that of our entire North American continent, in actuality. Red fox I can remember perfectly clear when the red fox was a “clear and present danger” to everyone’s free-ranging chicken flock. Those chickens would be both young hens (pullets) and frying pan roosters (cockerels) under one year of age. If you think foxes didn’t go after chickens early in the morning as they came out of a brooder house or flew down from the ever- present boxelder trees on a small farm of that era, you’d be wrong. I can remember well, my mom, at hearing a chicken commotion at sunup, in her precious chickens, holler for my dad. “The fox are in the chickens again!” Then him, grabbing his tight- choked Remington Model 10 pump shotgun from behind the front house door. It would be loaded and ready for action with No. 2 shot, 2ľ” baby magnums. That was definitely a fox load, not a pheas’ load! But it was seldom used because Reddy Fox had already grabbed one of those young, dumb leghorns but choice eating birds or soon to be layers and was heading down a knee-high corn row. Heading for its den, the mother or father of a litter of fox\n\ncubs, usually four per litter, and growing fast in June. That den would usually be on the southeast side of a hill so that the pups would come out and play in the sun each sunup. Well, that happened often enough throughout Murray County that a bounty was placed on fox, $4 for adults, $2 for cubs. But that pay for a dead fox was nothing compared to what happened in the 1960s','the foxes of North America\n\nGood luck with that! It’s been interesting to watch the ebb and flow of fox populations in southwest Minnesota. And, for that of our entire North American continent, in actuality. Red fox I can remember perfectly clear when the red fox was a “clear and present danger” to everyone’s free-ranging chicken flock. Those chickens would be both young hens (pullets) and frying pan roosters (cockerels) under one year of age. If you think foxes didn’t go after chickens early in the morning as they came out of a brooder house or flew down from the ever- present boxelder trees on a small farm of that era, you’d be wrong. I can remember well, my mom, at hearing a chicken commotion at sunup, in her precious chickens, holler for my dad. “The fox are in the chickens again!” Then him, grabbing his tight- choked Remington Model 10 pump shotgun from behind the front house door. It would be loaded and ready for action with No. 2 shot, 2ľ” baby magnums. That was definitely a fox load, not a pheas’ load! But it was seldom used because Reddy Fox had already grabbed one of those young, dumb leghorns but choice eating birds or soon to be layers and was heading down a knee-high corn row. Heading for its den, the mother or father of a litter of fox\n\ncubs, usually four per litter, and growing fast in June. That den would usually be on the southeast side of a hill so that the pups would come out and play in the sun each sunup. Well, that happened often enough throughout Murray County that a bounty was placed on fox, $4 for adults, $2 for cubs. But that pay for a dead fox was nothing compared to what happened in the 1960s',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:51','2026-03-25 00:55:51');
