INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_d19452d2-2195-5b8c-a680-b88ff544535b','Eagle girls stumble against Worthington','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','5','[6]','Eagle girls stumble against Worthington\n\nshot into the net for a power play goal. Then, at the 9:12 mark of the second, a scramble in front of the net during a power play saw Alayna Nelson poke the puck through the crowd into the net. Gretta Smith assisted on the play. But Worthington answered, taking a 5-2 lead late in the second period, then adding a power play goal early in the third to seal the win. Worthington outshot the\n\nEagles 68-13 in the game. Goalie Fiona Robillard finished with 62 saves. Worthington.............................................2 3 1 — 6 Windom Area...........................................0 2 0 — 2 FIRST PERIOD: 1. Worthington: Madelyn Cummings (Tayler Nickel, Leah Nelson) 3:18. 2. Worthington: Nelson (u/a) 14:10. SECOND PERIOD: 3. Worthington: Breeta Johnsson (Nickel) 0:25. 4. Worthington: Johnsson (u/a) 4:04. 5. Windom: Alicia Meyeraan (u/a) 9:12, pp. 6. Windom: Alayna Nelson (Gretta Smith) 12:54, pp. 7. Worthington: Alianna Bristow (Catlyn Freking) 14:39. THIRD PERIOD: 8. Worthington: Victoria Bush (Bristow) 1:26, pp. SUMMARY: Shots on goal: Worthington 68, Windom 13. Power plays: Worthington 1-4, Windom 2-2. Goalies: Worthington, Macie Mahlberg (13 shots, 11 saves); Windom, Fiona Robillard (68 shots, 62 saves).','Eagle girls stumble against Worthington\n\nshot into the net for a power play goal. Then, at the 9:12 mark of the second, a scramble in front of the net during a power play saw Alayna Nelson poke the puck through the crowd into the net. Gretta Smith assisted on the play. But Worthington answered, taking a 5-2 lead late in the second period, then adding a power play goal early in the third to seal the win. Worthington outshot the\n\nEagles 68-13 in the game. Goalie Fiona Robillard finished with 62 saves. Worthington.............................................2 3 1 — 6 Windom Area...........................................0 2 0 — 2 FIRST PERIOD: 1. Worthington: Madelyn Cummings (Tayler Nickel, Leah Nelson) 3:18. 2. Worthington: Nelson (u/a) 14:10. SECOND PERIOD: 3. Worthington: Breeta Johnsson (Nickel) 0:25. 4. Worthington: Johnsson (u/a) 4:04. 5. Windom: Alicia Meyeraan (u/a) 9:12, pp. 6. Windom: Alayna Nelson (Gretta Smith) 12:54, pp. 7. Worthington: Alianna Bristow (Catlyn Freking) 14:39. THIRD PERIOD: 8. Worthington: Victoria Bush (Bristow) 1:26, pp. SUMMARY: Shots on goal: Worthington 68, Windom 13. Power plays: Worthington 1-4, Windom 2-2. Goalies: Worthington, Macie Mahlberg (13 shots, 11 saves); Windom, Fiona Robillard (68 shots, 62 saves).',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:52','2026-03-25 00:55:52');
INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_3794d164-896a-53b7-9bdf-e2cdb4042422','Eagle boys snap skid, win a pair','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','6',NULL,'Eagle boys snap skid, win a pair\n\nWorthington cut the deficit to 2-1 early in the third, but Parker netted an unassisted power play goal at the 11:18 mark of the second, pushing the lead to 3-1. The Trojans again cut into the deficit at the 12:16 mark of the second, but 40 seconds later, Weston Murray took a feed from Ayden Endreson and pushed the lead back to two goals for the Eagles. A goal by Jessy Gentry with 1:47 left in the second period gave the Eagles a 5-2 lead. A goal from Daniel Staples pushed the lead to 6-2 early in the third and Endreson netted a goal with six minutes to play to seal the win. The Eagles outshot Worthington 35-32 for the game. Kole Espenson finished with 29 saves in the win. Worthington..........................................0 1 2 — 3 Windom Area........................................2 3 2 — 7 FIRST PERIOD: 1. Windom: Jonah Lohse (Gavin McNamara) 0:58. 2. Windom: Bodi Parker (Cormac Raderstorf) 3:05. SECOND PERIOD: 3. Worthington: Kaden Khamphanh (Noahh Hohenstein) 5:26. 4. Windom: Parker (u/a) 11:18, pp. 5. Worthington: Ryker Thier (Hohenstein, Hunter Heitkamp) 12:16. 6. Windom: Weston Murray (Nash Dietz, Ayden Endreson) 12:56. 7. Windom: Jessy Gentry (Andrei Rivera) 15:13. THIRD PERIOD: 8. Windom: Daniel Staples (Dietz) 3:08. 9. Worthington: Thier (Heitkamp, Dominic Pavelko) 6:48, pp. 10. Windom: Endreson (u/a) 11:05. SUMMARY: Shots on goal: Worthington 32, Windom 35. Power plays: Worthington 1-3, Windom 1-5. Goalies: Worthington, Tyson Petersen (35 shots, 28 saves); Windom, Kole Espenson (32 shots, 29 saves). Eagles fall at Marshall The Windom Area boys hockey team saw its losing streak run to seven games Tuesday after a 3-1 loss at Marshall. Complete details of last Tuesday’s game appear on windomnews.com. Windom Area........................................1 0 0 — 1 Marshall...............................................0 3 0 — 3 FIRST PERIOD: 1. Windom: Daniel Staples (u/a) 3:39. SECOND PERIOD: 2. Marshall: Jacob Allen (Nate Drown) 0:52. 3. Marshall: Morgan Rokeh (Carson Kopitski) 11:49. 4. Marshall: Allen (Tate Mellenthin) 16:03. THIRD PERIOD: No scoring. SUMMARY: Shots on goal: Windom 15, Marshall 27. Power plays: Windom 0-2, Marshall 0-5. Goalies: Windom, Kole Espenson (27 shots, 24 saves); Marshall, McCoy Guenther (15 shots, 14 saves).','Eagle boys snap skid, win a pair\n\nWorthington cut the deficit to 2-1 early in the third, but Parker netted an unassisted power play goal at the 11:18 mark of the second, pushing the lead to 3-1. The Trojans again cut into the deficit at the 12:16 mark of the second, but 40 seconds later, Weston Murray took a feed from Ayden Endreson and pushed the lead back to two goals for the Eagles. A goal by Jessy Gentry with 1:47 left in the second period gave the Eagles a 5-2 lead. A goal from Daniel Staples pushed the lead to 6-2 early in the third and Endreson netted a goal with six minutes to play to seal the win. The Eagles outshot Worthington 35-32 for the game. Kole Espenson finished with 29 saves in the win. Worthington..........................................0 1 2 — 3 Windom Area........................................2 3 2 — 7 FIRST PERIOD: 1. Windom: Jonah Lohse (Gavin McNamara) 0:58. 2. Windom: Bodi Parker (Cormac Raderstorf) 3:05. SECOND PERIOD: 3. Worthington: Kaden Khamphanh (Noahh Hohenstein) 5:26. 4. Windom: Parker (u/a) 11:18, pp. 5. Worthington: Ryker Thier (Hohenstein, Hunter Heitkamp) 12:16. 6. Windom: Weston Murray (Nash Dietz, A