INSERT OR REPLACE INTO articles (doc_id,title,author,publish_date,source_file,location,subjects,summary,url,publisher,edition_id,section,start_page,continuation_pages,full_text,cleaned_text,subheadline,organization_id,publication_id,status,duplicate_flag,needs_review,parse_metadata_json,updated_at,created_at) VALUES ('quadd_31_7d179b18-b9ef-5e66-9838-6053d820f229','DNR urges snowmobilers to practice safety','','2026-01-28','quadd_extraction','Cottonwood County, MN',NULL,NULL,NULL,'Observer/Advocate','31','news','6',NULL,'DNR urges snowmobilers to practice safety\n\nhelp ensure a safe ride: • Know where you can ride. Riders who stay on marked trails are less likely to strike an obstacle or trespass onto private property. Riders should also check trail conditions (mndnr.gov/ snow_depth) before heading out. • Avoid alcohol before and during a ride. Drinking plays a role in about 60% of fatal snowmobile crashes. • Watch your speed. Going too fast is another main factor in crashes. Many serious and fatal crashes occur when a speeding snowmobiler loses control or strikes an object. • Ride on the right. This is an important factor in helping prevent head-on crashes on trails. • Be careful on the ice. Obstacles such as pressure ridges have been common this year. Also, be aware of ice thickness — there must be at least 5 to 7 inches of new, clear ice to support the weight of a snowmobile and rider. • Take a snowmobile safety course. It’s required for anyone born after 1976 and recommended for everyone. People with a snowmobile safety certification (mndnr. gov/safety/vehicle/snowmobile) are less likely to be involved in serious or fatal crashes. The DNR has more safety tips on its snowmobiling safety webpage (mndnr.gov/ snowmobiling/safety.html) and its ice safety webpage (mndnr.gov/safety/ice/index.html).','DNR urges snowmobilers to practice safety\n\nhelp ensure a safe ride: • Know where you can ride. Riders who stay on marked trails are less likely to strike an obstacle or trespass onto private property. Riders should also check trail conditions (mndnr.gov/ snow_depth) before heading out. • Avoid alcohol before and during a ride. Drinking plays a role in about 60% of fatal snowmobile crashes. • Watch your speed. Going too fast is another main factor in crashes. Many serious and fatal crashes occur when a speeding snowmobiler loses control or strikes an object. • Ride on the right. This is an important factor in helping prevent head-on crashes on trails. • Be careful on the ice. Obstacles such as pressure ridges have been common this year. Also, be aware of ice thickness — there must be at least 5 to 7 inches of new, clear ice to support the weight of a snowmobile and rider. • Take a snowmobile safety course. It’s required for anyone born after 1976 and recommended for everyone. People with a snowmobile safety certification (mndnr. gov/safety/vehicle/snowmobile) are less likely to be involved in serious or fatal crashes. The DNR has more safety tips on its snowmobiling safety webpage (mndnr.gov/ snowmobiling/safety.html) and its ice safety webpage (mndnr.gov/safety/ice/index.html).',NULL,NULL,NULL,'parsed','0','0',NULL,'2026-03-25 00:55:52','2026-03-25 00:55:52');
